import { isUndefined } from 'lodash-es';

import { MarkerInteractionState } from '../types/marker.js';
import { SelectionState } from '../types/state.js';

export const buildMarkerBrightnessState = (
  { data, hoveredGroup, hoveredListItem, pinnedGroup }: SelectionState,
  markerId: string,
  isHoveringListItem: boolean,
): MarkerInteractionState => {
  let state: MarkerInteractionState = 'default';
  if ((pinnedGroup ?? hoveredGroup) && data) {
    const markersIdWithinGroup = data.map(({ key }) => key);
    if (markersIdWithinGroup.includes(markerId)) {
      if (isUndefined(pinnedGroup)) {
        state = 'hovered';
      } else if (isUndefined(hoveredListItem)) {
        state = 'active';
      } else {
        state = isHoveringListItem ? 'active' : 'inactive';
      }
    }
  }

  return state;
};
